            const numStr = input.substring(i, j);
            const value = parseInt(numStr, 10);
            tokens.push({ type: TOK.NUMBER, value });
            i = j;
        } else if (ch === '+') {
            tokens.push({ type: TOK.PLUS });
            i++;
        } else if (ch === '-') {
            tokens.push({ type: TOK.MINUS });
            i++;
        } else if (ch === '*') {
            tokens.push({ type: TOK.TIMES });
            i++;
        } else if (ch === '/') {
