    }

    private parseExpr(): number {
        let result = this.parseTerm();
        while (this.peek() && (this.peek().type === TOK.PLUS || this.peek().type === TOK.MINUS)) {
            const op = this.consume();
            const right = this.parseTerm();
            if (op.type === TOK.PLUS) {
